// Generated by CLI Printing Press, hand-extended for HTTP transport.

package main

// PATCH mcp-http-transport: added --http :addr flag for Streamable HTTP transport (printing-press v4.2.0 dropped mcp.transport from spec — cli-printing-press#825).

import (
	"flag"
	"fmt"
	"os"

	"github.com/mark3labs/mcp-go/server"
	mcptools "github.com/mvanhorn/printing-press-library/library/ai/openrouter/internal/mcp"
)

func main() {
	httpAddr := flag.String("http", "", "If set (e.g. :8092), serve over Streamable HTTP instead of stdio")
	flag.Parse()

	s := server.NewMCPServer(
		"Openrouter",
		"1.0.0",
		server.WithToolCapabilities(false),
	)
	mcptools.RegisterTools(s)

	if *httpAddr != "" {
		fmt.Fprintf(os.Stderr, "openrouter-pp-mcp: serving Streamable HTTP on %s\n", *httpAddr)
		hs := server.NewStreamableHTTPServer(s)
		if err := hs.Start(*httpAddr); err != nil {
			fmt.Fprintf(os.Stderr, "MCP HTTP server error: %v\n", err)
			os.Exit(1)
		}
		return
	}

	if err := server.ServeStdio(s); err != nil {
		fmt.Fprintf(os.Stderr, "MCP server error: %v\n", err)
		os.Exit(1)
	}
}
